function renderLasijums(lasijums, nr, arLugsanu = false) {
  return `
    <hr>
    <h4><span class="redbold">${nr} LASĪJUMS</span></h4>
    <p>
      <span class="backbold">${lasijums.lasijumstitle}</span>
      <span class="sarkans">${lasijums.lasijumaRef}</span>
    </p>
    <p style="text-align: center;">
      <span class="italic">${lasijums.lasijumsNos}</span>
    </p>
    <p>${lasijums.lasijumstext}</p>
    ${arLugsanu ? `
      <hr>
      <h4><span class="redbold">LŪGŠANA</span></h4>
      <div class="noslegumaLugsana">
        <p>${lasijums.lugsana}</p>
      </div>
    ` : ''}
  `;
}

